function estado_visita()
{ 
	if (Ctrl('main').GetMode()=='LIST_CONTROL')
	{	                                   
			Ctrl('main').DoEvent("Estado_visita");
	}	
}
function get_visitantes_vencidos()
{                

		if(Ctrl("visitantes_list").GetXValue()!="")
		{  
			contador_vencidos=Ctrl("contador_visitantes_vencidos").GetXValue();
			//le resto uno para tener la cantidad de comas
			contador_vencidos1= contador_vencidos - 1; 
			var vencidos = "Listado de los primeros 10 Visitantes Vencidos:" + "\n" + Ctrl("visitantes_list").GetXValue();

			bandera = 1
			for(i=0; i<contador_vencidos1; i++)
			{
				bandera = bandera + 1;
				if(bandera<11)
				{
					var vencidos = vencidos.replace(",", "\n");
				}
			}
			alert(vencidos);
	  }
} 

var g_excedidos;
function get_visitantes_excedidos()
{                
		if(Ctrl("visitantes_list").GetXValue()!="")
		{    
			contador_excedidos=Ctrl("contador_visitantes_excedidos").GetXValue();
			//le resto uno para tener la cantidad de comas
			contador_excedidos1= contador_excedidos - 1;
			var excedidos= "Listado de los primeros 10 Visitantes Excedidos en Horas y Minutos:" + "\n" + Ctrl("visitantes_list").GetXValue();
			bandera = 1
			for(i=0; i<contador_excedidos1; i++)
			{
				bandera = bandera + 1;
				if(bandera<11)
				{
					excedidos = excedidos.replace(",", "\n");
				}
			}

	  	g_excedidos = excedidos;
	  	setTimeout("alert(g_excedidos);", 100);
	  }
}

function valido_egreso()
{    
	if (Ctrl('main').GetMode()=='LIST_CONTROL')
	{    
		img=Ctrl("LIST1").GetSelectAttrValue("img").toUpperCase().split("/");
		img=img[img.length-1].split(".")[0];
		switch(img)   //SI SON ROJOS(Vencidos) BLOQUEO BOTON EGRESO
		{
			case "SGB":
				CtrlEnabled("EGRESO"  ,true);
			break;
			case "SOB":
				CtrlEnabled("EGRESO"  ,true);
			break;  

			default:
				CtrlEnabled("EGRESO"  ,false);
				alert("No se puede egresar si no está En curso o Excedida");
				return(false);
			break; 
		}

		if (Ctrl("LIST1").shownRegs.length==0)//SI NO HAY REGISTRO EN EL LISTADO DESHABILITO BOTONES
		{
			Ctrl("EGRESO").SetEnabled(false);
			alert("Seleccionar un visitante");
		}
		else// SI HAY REGISTROS EN EL LISTADO HABILITO EGRESO
		{	
			Ctrl("EGRESO").SetEnabled(true);
			Ctrl('main').DoEvent('EDITEGRESORAPIDO');
		}	
	} 

}
function LOAD()
{	

  if (Ctrl('main').GetMode()=='VISITA_RAPIDO')
  {
  	//alert("VISITA_RAPIDO");
  	EnableControls();
  	Ctrl('e_cantidad_hid').SetXValue('1');                    
  	//if(Ctrl('oi_visitante').GetXValue() == ''){	Ctrl('f_fechahora_ent_es').SetTypedValue(Now());	}

   	/*si vuelta es igual a 1 significa que se eligió un visitante (funcion select_visitante()) 
   	y vuelve a cargar la funtion LOAD()*/ 
  	if(vuelta != 1)
  	{    
  		hoy = fecha_actual();
  		hoy = hoy+'00'; 
  	  Ctrl('f_fechahora_ent').SetTypedValue(Now());
  		//Ctrl('f_fechahora_ent_es').SetTypedValue(Now());
  		Ctrl('f_fechahora_ent_es_hid').SetXValue(hoy); 
  		Ctrl('oi_visitante').SetXValue('');
			Ctrl('oi_foto').SetXValue('');
			Ctrl('f_fechahora_sal_es').SetXValue('');
			Ctrl('d_credencial').SetXValue('');
			Ctrl('f_fechahora_en_ent').SetXValue('');  	
			Ctrl('f_fechahora_sal_en').SetXValue('');
			//Ctrl('f_fechahora_sal').SetXValue('');
			Ctrl('l_casco').SetXValue('');
			Ctrl('l_anteojos').SetXValue('');
		} 
	  //alert("Visitante2: "+Ctrl("oi_visitante2").GetXValue());
		if(Ctrl("oi_visitante2").GetXValue()!='')
  	{
  		Ctrl("oi_visitante").SetXValue(Ctrl("oi_visitante2").GetXValue());
  		Ctrl('oi_visitante2').SetXValue('');
  	}
  }

  if (Ctrl('main').GetMode()=='LIST_CONTROL')
  {  
		if(Ctrl("estado_vis").GetXValue()=="" && Ctrl("iter_search").GetCValue()=="")
		{   
  		setTimeout("REFR()",Ctrl('MinRefresh').GetXValue() * 60 * 1000)

  		var window_actual=GetRootWindow().g_objFormManager.GetActiveWindowFrame(); //	ID Pantalla actual
			var window_control_visita = g_FFConnect.MultiMode; // ID Pantalla de Control de visitas
		  if(window_actual==window_control_visita)
		  	get_visitantes_excedidos();   //get_visitantes_vencidos();   
  	} 

  	/*SI ES IGUAL A 2 SIGNIFICA QUE YA ENTRÓ A LA FUNCIÓN Y EJECUTÓ EL QUERY Estado_visita en el flow. CUANDO VUELVE AL FORMULARIO EJECUTA
  	EL LOAD, COMO VUELTA ES IGUAL A 2 NO VUELVE A EJECUTAR EL QUERY Estado_visita. */
  	if(vuelta!=2)   
  	{ 
  		vuelta = 2;                         
	  	if(Ctrl("estado_vis").GetXValue()!="")
	  	{          
	  		Ctrl('main').DoEvent("Estado_visita");
	  	}             
		} 

  	if (Ctrl("LIST1").shownRegs.length!=0)
  	{
	  	img=Ctrl("LIST1").GetSelectAttrValue("img").toUpperCase().split("/");
			img=img[img.length-1].split(".")[0]; 
			switch(img)   //SI NO ES VERDE(En curso) O NARANJA (Excedido) BLOQUEO BOTON EGRESO
			{
				case "SGB":
					CtrlEnabled("EGRESO"  ,true);
				break;
				case "SOB":
					CtrlEnabled("EGRESO"  ,true);
				break;  

				default:
					CtrlEnabled("EGRESO"  ,false);
				break; 
			}
	  }
	  else
	  	CtrlEnabled("EGRESO"  ,false);

  	if (Ctrl("LIST1").shownRegs.length==0)
  	{
			Ctrl("VISITA").SetEnabled(false);
		}
		else
		{
			Ctrl("VISITA").SetEnabled(true);
		}
  } 
  if (Ctrl('main').GetMode()=='SHOW_CONTROL')
	{ 
		//alert(Ctrl('oi_visita').GetXValue()); 
		Ctrl("e_cantidad").SetEnabled(false);
	  if(Ctrl('oi_visita').GetXValue()!="");           	
			validar_botones();  
	}

  if (Ctrl('main').GetMode()=='NEW')
  {    
  	Ctrl('f_fechahora_ent_es').SetTypedValue(Now());
  	Ctrl("e_cantidad").SetEnabled(false);

  	//alert("e_cantidad: "+Ctrl('e_cantidad').GetXValue()); 
  	//alert("cantidad_visitantes: "+Ctrl('cantidad_visitantes').GetXValue());

  	if(Ctrl('cantidad_visitantes').GetXValue() != '')
  		Ctrl('e_cantidad').SetXValue(Ctrl('cantidad_visitantes').GetXValue());
  }

  if (Ctrl('main').GetMode()=='EDIT')
  {                                                 
  	Ctrl("e_cantidad").SetEnabled(false);
  	if(Ctrl('cantidad_visitantes').GetXValue() != '')
  		Ctrl('e_cantidad').SetXValue(Ctrl('cantidad_visitantes').GetXValue());
  }
  if (Ctrl('main').GetMode()=='SHOW') 
  	validar_botones(); 

  if (Ctrl('main').GetMode()=='LIST')
  	validar_botones();  
}

function REFR()
{	 
	if (Ctrl('main').GetMode()=='LIST_CONTROL')
  {  
   	if (Ctrl('LIST1'))
	  {  	
	  	if(Ctrl("estado_vis").GetXValue()=="" && Ctrl("iter_search").GetCValue()=="") 
	  		Ctrl('main').DoEvent("QRYREFRESH");  	
	  }
	}
}    

function Find()
{                  
	if (Ctrl('main').GetMode()=='LIST_CONTROL')
		Ctrl("LIST1").filter("",Ctrl("iter_search").GetCValue());

	if (Ctrl('main').GetMode()=='LIST_EDIT' || Ctrl('main').GetMode()=='LIST')
		Ctrl("LIST").filter("",Ctrl("iter_search").GetCValue());
	//Ctrl("LIST1").filter("d_ape_y_nom",Ctrl("iter_search").GetCValue());
}


function REFRESH()
{
	Ctrl("LIST1").Refresh();
}  

function OnActivate()
{                      
  if (Ctrl('main').GetMode()=='LIST_CONTROL')
  {
  	//Cargo la Lista
  	Ctrl('LIST1').Refresh();
  }
}   

