function ListClickControl()
{		
	var img;
	if (Ctrl('main').GetMode()=='LIST_CONTROL')
	{
		img=Ctrl("LIST1").GetSelectAttrValue("img").toUpperCase().split("/");
		img=img[img.length-1].split(".")[0];

		switch(img)
		{
			case "SGB":
				CtrlEnabled("EGRESO"  ,true);
			break;
			case "SOB":
				CtrlEnabled("EGRESO"  ,true);
			break;  

			default:
				CtrlEnabled("EGRESO"  ,false);
			break; 
		}
	}
	if (Ctrl('main').GetMode()=='LIST')
	{       
		validar_botones();
	}   
} 
function validar_botones()
{                                   
	if (Ctrl('main').GetMode()=='LIST')
	{
		//alert(Ctrl("LIST").GetSelectAttrValue("id"));
		var oi_visita = Ctrl("LIST").GetSelectAttrValue("id");             
		var nSQL = GetProxy().SQLService();  
		var param =  '<SOURCE oi_visita="'+ oi_visita + '"/>';             
	}
	if (Ctrl('main').GetMode()=='SHOW')
	{   
		var oi_visita = Ctrl('oi_visita_show').GetXValue();             
		var nSQL = GetProxy().SQLService();  
		var param =  '<SOURCE oi_visita="'+ oi_visita + '"/>'; 
	}	 
	if (Ctrl('main').GetMode()=='SHOW_CONTROL')
	{   
		var oi_visita = Ctrl('oi_visita').GetXValue();             
		var nSQL = GetProxy().SQLService();  
		var param =  '<SOURCE oi_visita="'+ oi_visita + '"/>';
	}
		//Cada query devuelve la cantidad de visitantes por la visita y estado
		var en_curso = nSQL.GetOBJ(Ctrl("main").getResource("QRY_ValidaEnCurso"), param);
		var egresada = nSQL.GetOBJ(Ctrl("main").getResource("QRY_ValidaEgresada"), param);
		var no_iniciada = nSQL.GetOBJ(Ctrl("main").getResource("QRY_ValidaNoIniciada"), param);
		var excedida = nSQL.GetOBJ(Ctrl("main").getResource("QRY_ValidaExcedida"), param); 

		/*alert("en_curso: "+en_curso.COUNT);
		alert("egresada: "+egresada.COUNT);
		alert("no_iniciada: "+no_iniciada.COUNT);
		alert("excedida: "+excedida.COUNT); */
		//Si es en_curso.COUNT es igual a 0 significa que la visita no tiene visitantes En curso para poder egresar
		if(en_curso.COUNT=='0')
		{                     
				Ctrl("PRINT").SetEnabled(false);
        //inhabilito Egresos
				if(excedida.COUNT=='0')
					Ctrl("EGRESOS").SetEnabled(false);     
				else
					Ctrl("EGRESOS").SetEnabled(true);

				if(egresada.COUNT=='0')
				{  
					if(no_iniciada.COUNT=='0')
					{  
						Ctrl("INGRESO").SetEnabled(false);
					}
					else 
					{     
						Ctrl("INGRESO").SetEnabled(true); 	
					}
				}
				else 
				{     
					Ctrl("INGRESO").SetEnabled(false); 	
				} 
		}
		else 
		{  
			Ctrl("PRINT").SetEnabled(true);
			Ctrl("EGRESOS").SetEnabled(true);
			Ctrl("INGRESO").SetEnabled(true); 	
		} 

}
