function valido_pase()
{ 
	if (Ctrl('main').GetMode()=='SHOW_CONTROL')
	{           

		var oi_visita = Ctrl('oi_visita').GetXValue();             
		var nSQL = GetProxy().SQLService();
		var visitantes_vencidos= nSQL.GetOBJ(Ctrl("main").getResource("QRY_Get_visitantes_vencidos"), "");  
		//alert("venci "+visitantes_vencidos.oi_visitante); 
		if(visitantes_vencidos.oi_visitante!="0")
		{    
			//alert("con visitante");
			var param =  '<SOURCE oi_visita="'+ oi_visita + '" oi_visitantes="'+ visitantes_vencidos.oi_visitante +'" />'; 
		} 
		else
		{
			//alert("sin visitante");
			var param =  '<SOURCE oi_visita="'+ oi_visita + '" />';             
		}

		var visita = nSQL.GetOBJ(Ctrl("main").getResource("QRY_ValidarPaseDeVisita"), param);

		//alert(visita.COUNT);
		//COUNT="0"
		if(visita.COUNT=='0')
		{  
			return false;
		}
	}
	Ctrl("main").DoEvent("PRINT1"); 
}

