function valido_save()
{         
	if (Ctrl('main').GetMode()=='NEW' || (Ctrl('main').GetMode()=='EDIT'))
  {     
		var ent_estipulada = Ctrl('f_fechahora_ent_es').GetXValue();                    
		ent_est = ent_estipulada.substr(0,12)  
    hoy = fecha_actual();

		if(ent_est < hoy)
		{	
			alert("La Fecha-Hora Entrada Estipulada debe ser mayor o igual a la Fecha-Hora del día de hoy");
			return false;
		}  
	}
	Ctrl("main").DoEvent("SAVE"); 
}           

function fecha_actual(){
    date = new Date();
		//MES
		month=date.getMonth() + 1; 
		var longitud_month=month.toString().length;
		var month2 = month.toString(); 
		if(longitud_month == 1)
		{  
			month2="0"+month2;   
		}
		//DÍA
		day = date.getDate().toString();
		var longitud_day=day.toString().length;
		if(longitud_day == 1)
		{
			day="0"+day;
		}          
		//HORAS
		hora=date.getHours().toString();
		var longitud_hora=hora.toString().length;
		if(longitud_hora == 1)
		{
			hora="0"+hora;
		}
		//MINUTOS       
		min = date.getMinutes().toString();
		var longitud_min=min.toString().length;
		if(longitud_min == 1)
		{
			min="0"+min;
		}       
		/*alert("Mes: "+month2);
		alert("Día: "+day);
		alert("Hora: "+hora);
		alert("min: "+min);*/
		//var hoy= date.getFullYear().toString()+month2+date.getDate().toString()+date.getHours().toString()+date.getMinutes().toString();   
    hoy= date.getFullYear().toString()+month2+day+hora+min;   
    /*alert("ESTIP: "+ent_est);
    alert("HOY: "+hoy);*/   
    return hoy;
}
